1577     if (!Cmp.isEquality() && XorC->isSignMask()) {
1578       Pred = Cmp.getFlippedSignednessPredicate();
1579       return new ICmpInst(Pred, X, ConstantInt::get(X->getType(), C ^ *XorC));
1580     }
